div.style:
min-height: 100vh;
background: #f0eeff;
font-family: 'Segoe UI', system-ui, -apple-system, sans-serif;
box-sizing: border-box;

display: flex;
align-items: center;
justify-content: space-between;
padding: 14px 32px;
background: #fff;
border-bottom: 1px solid rgba(124,110,247,.18);
box-shadow: 0 2px 12px rgba(124,110,247,.08);
position: sticky;
top: 0;
z-index: 20;
gap: 16px;

button.style:
background: #f0eeff;
color: #7c6ef7;
border: 1.5px solid rgba(124,110,247,.3);
border-radius: 50px;
padding: 7px 18px;
font-size: 13px;
font-weight: 600;
cursor: pointer;
white-space: nowrap;

background: linear-gradient(135deg,#7c6ef7,#5a50c8);
color: #fff;
border: none;
border-radius: 50px;
padding: 9px 22px;
font-size: 13px;
font-weight: 600;
cursor: pointer;
box-shadow: 0 4px 14px rgba(124,110,247,.35);
white-space: nowrap;

input.style:
border: 1.5px solid rgba(124,110,247,.25);
border-radius: 8px;
padding: 8px 12px;
font-size: 13px;
color: #2d2d4e;
background: #fff;
outline: none;

border: 1.5px solid rgba(124,110,247,.25);
border-radius: 8px;
padding: 8px 14px;
font-size: 13px;
color: #2d2d4e;
background: #fff;
outline: none;
width: 220px;

div.style:
display: grid;
grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
gap: 18px;
padding: 28px 32px;

grid-column: 1/-1;
text-align: center;
padding: 80px 20px;
color: #a0a0c0;
font-size: 15px;

background: #fff;
border: 1.5px solid rgba(124,110,247,.15);
border-radius: 16px;
padding: 0;
cursor: pointer;
box-shadow: 0 2px 12px rgba(124,110,247,.08);
overflow: hidden;
transition: transform .2s, box-shadow .2s;
display: flex;
flex-direction: column;

background: linear-gradient(135deg,#7c6ef7,#5a50c8);
padding: 12px 16px;
display: flex;
align-items: center;
justify-content: space-between;

background: #f0eeff;
border: 1px solid rgba(124,110,247,.2);
border-radius: 8px;
padding: 4px 12px;
font-size: 14px;
font-weight: 700;
color: #7c6ef7;
